<template >
<div style="margin-top: 20px;" >
   <nav-component></nav-component>
    <div class="container shift ">
          <div id="full-clndr" class="clearfix ">
          <script type="text/template" id="full-clndr-template">

      
            <div class="clndr-controls">
              <div class="clndr-previous-button">&lt;</div> 
              <div class="current-month"><%= month %> <%= year %></div>
              <div class="clndr-next-button">&gt;</div>
            </div>
         
            <div class="clndr-grid">
              <div class="days-of-the-week clearfix">
                <% _.each(daysOfTheWeek, function(day) { %>
                  <div class="header-day"><%= day %></div>
                <% }); %>
              </div>
              <div class="days">
                <% _.each(days, function(day) { %>
                  <div class="<%= day.classes %>" id="<%= day.id %>">
                    <span class="day-number"><%= day.day %></span>
                  </div>
                <% }); %>
              </div>
            </div>

            <div class="event-listing">
              <div class="event-listing-title">EVENTS THIS MONTH</div>
              <% _.each(eventsThisMonth, function(event) { %>
                  <div class="event-item">
                    <div class="event-item-name"><%= event.title %></div>
                    <div class="event-item-location"><%= event.location %></div>
                    <div class="event-item-members <%= event.category %>"><%= event.members %></div>
                  </div>
                <% }); %> 
                
            </div>

      
          </script>
        </div>

      <div class="event-key boxshadow">
        <li class="key"><span class="key-nino">.</span>Ninos</li>
        <li class="key"><span class="key-jov">.</span>Jovenes</li>
        <li class="key"><span class="key-anc">.</span>Ancianos</li>
        <li class="key"><span class="key-mat">.</span>Matrimonio</li>
        <li class="key"><span class="key-con">.</span>Congregacional</li>
      </div>
    </div>

</div>



 
</template>

<script>
import Nav from './main/Nav.vue';

export default {
  name: 'Events2',
  components: {
    'nav-component': Nav
  },
  methods: {
    calendar(){
         var clndr = {};

          $( function() {


            // PARDON ME while I do a little magic to keep these events relevant for the rest of time...
            var currentMonth = moment().format('YYYY-MM');
            var feb    = moment().add('month', 1).format('YYYY-MM');
            var mar    = moment().add('month', 2).format('YYYY-MM');
            

            var events = [
              { date: currentMonth + '-' + '10', title: 'Persian Kitten Auction', location: 'Center for Beautiful Cats', category:'nino' },
              { date: currentMonth + '-' + '19', title: 'Cat Frisbee', location: 'Jefferson Park', category:'jov' },
              { date: currentMonth + '-' + '23', title: 'Kitten Demonstration', location: 'Center for Beautiful Cats', category:'nino' },
              { date: feb + '-' + '07', title: 'Small Cat Photo Session', location: 'Center for Cat Photography', category:'jov' },
              { date: mar + '-' + '15', title: 'bala', location: 'Center for Cat Photography', category:'anc' }
            ];

            clndr = $('#full-clndr').clndr({
              template: $('#full-clndr-template').html(),
              daysOfTheWeek: ['Dom','Lu', 'Mar', 'Mier', 'Jue', 'Vie', 'Sab'],
              events: events,
              dateParameter: 'date',
              cateParameter: 'category',
              adjacentDaysChangeMonth: true,
              forceSixRows: false
              
            });

             var arrayCat = [];
             var test = document.getElementsByClassName('event')
            console.log(test)
            for (var i=0; i < test; i++){
             
              console.log(test)
            };
          
            for (var i=0; i < events.length; i++){
             
              arrayCat.push(events[i].category);

              // $(test).addClass(events[i].category)

            };
            // console.log(test)
              console.log(arrayCat)
            
            $.each(arrayCat, function(i, val) {

              //  var res = $('.event').addClass(val)



            })
             
          });


           
    }
  },
  mounted(){
    this.calendar();
  }
}
</script>

<style lang="scss">



.clearfix:after {
  content: ".";
  display: block;
  clear: both;
  visibility: hidden;
  line-height: 0;
  height: 0;
}
.clearfix {
  display: inline-block;
}
html[xmlns] .clearfix {
  display: block;
}
* html .clearfix {
  height: 1%;
}

#full-clndr {
  margin: 30px auto;
  font-size: 14px;

  .clndr-controls {
      width: 100%;
      position: relative;
      margin-bottom: 20px;
      display: inline-block;
    
        div {
          margin: 7vw;
          display: inline;
          cursor: pointer;
        }
         .current-month {
            font-size: 20px;
          }
          .clndr-next-button, .clndr-previous-button {
            font-size: 20px;
            font-weight: bold;
          }
  }


  
  .clndr-grid {
      float: left;
      width: 65%;


      .days-of-the-week {
        width: 100%;
        .header-day {
          display: inline;
            margin: 2.8vw;
            font-size: 12px;
            font-weight: bold;
            text-align: center;
        }
    }

      .days {
        width: 100%;
        .day {
          display: inline-block;
          float: left;
          padding: 24px 0px;
          text-align: center;
          font-size: 2em;
          width: 14.2857%;
          border-bottom: 2px solid #f76b5b;
          border-left: 2px solid white;
        }

        .day.today {
          color: white;
          background: #5a93f5;
          font-weight: bold;
          opacity: .5;
        
        }

        .day.nino { background-color: #f76e38;}
        .key-jov { background-color: #37f78d;}
        .key-anc { background-color: #37c0f7;}
        .key-mat { background-color: #ca84f9;}
        .key-con { 
          background: rgba(247,107,91,1);
          background: -moz-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          background: -webkit-gradient(left top, right bottom, color-stop(0%, rgba(247,107,91,1)), color-stop(100%, rgba(90,147,245,0.58)));
          background: -webkit-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          background: -o-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          background: -ms-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          background: linear-gradient(135deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          filter: progid:DXImageTransform.Microsoft.gradient( startColorstr='#f76b5b', endColorstr='#5a93f5', GradientType=1 );
  }

        .day.event span{
          animation: pulse 2s infinite;
            padding: 5px 8px 5px 8px; 
          border-radius: 100%;
          font-weight: bold;
          color: white;
          // background: rgba(247,107,91,1);
          // background: -moz-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          // background: -webkit-gradient(left top, right bottom, color-stop(0%, rgba(247,107,91,1)), color-stop(100%, rgba(90,147,245,0.58)));
          // background: -webkit-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          // background: -o-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          // background: -ms-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          // background: linear-gradient(135deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
          // filter: progid:DXImageTransform.Microsoft.gradient( startColorstr='#f76b5b', endColorstr='#5a93f5', GradientType=1 );
        }

        .adjacent-month {
          opacity: .3;
          background: #eee;
        }
      }

  }

  .event-listing {
    width: 300px;
    float: right;
  
    .event-listing-title {
          text-align: center;
          font-size: 2vw;
          font-weight: bold;
        }
        .event-item {
          margin: 20px 0 80px 0;

          

          .event-item-name {
            font-weight: bold;

          }
    }
   
  }
 
}

.event-key{
  position: relative;
  left:0px;
  width: 700px;
  .key {
    display: inline;
    line-height: 20px;
    margin:0 0 0 20px;
  }
  span { display: inline-block;  margin: 5px; width: 20px; height: 20px; border-radius: 100%; }
        .key-nino { background-color: #f76e38;}
        .key-jov { background-color: #37f78d;}
        .key-anc { background-color: #37c0f7;}
        .key-mat { background-color: #ca84f9;}
        .key-con { 
              background: rgba(247,107,91,1);
                    background: -moz-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
                    background: -webkit-gradient(left top, right bottom, color-stop(0%, rgba(247,107,91,1)), color-stop(100%, rgba(90,147,245,0.58)));
                    background: -webkit-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
                    background: -o-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
                    background: -ms-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
                    background: linear-gradient(135deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.58) 100%);
                    filter: progid:DXImageTransform.Microsoft.gradient( startColorstr='#f76b5b', endColorstr='#5a93f5', GradientType=1 );
            }
 

}


</style>


