<template>
<div style="position: fixed; z-index: 99;">
    <div class="wrapper">
    <nav id="sidebar" >
                    <img class="logo" src="../../assets/img/NewLogo-01.svg" alt="">
                    <!-- <h4 style="padding:35px 0 0 15px;">Iglesia de Cristo</h4> -->
                <ul class="list-unstyled components">
                    <li class="active">
                        <router-link to="/" data-toggle="collapse" aria-expanded="false">
                             <img class="icon" src="../../assets/img/icons/house.svg" alt="" >
                            <h4>Home</h4> 
                        </router-link>
                    </li>
                    
                    <li>
                        <router-link to="/growth">
                             <img class="icon" src="../../assets/img/icons/head.svg" alt="">
                            <h4>Evangelio</h4>
                        </router-link>
                        <!-- <div id="studySub" >
                            <li class="studySubLink"><a>Video</a></li>
                            <li class="studySubLink"><a>Audio</a></li>
                            <li class="studySubLink"><a>Himnos</a></li>
                        </div> -->
                    </li>
                    <li>
                        <router-link to="/events">
                             <img class="icon" src="../../assets/img/icons/calendar.svg" alt="">
                            <h4>Event</h4>
                        </router-link>
                    </li>
                     <li>
                        <router-link to="/contact">
                             <img class="icon" src="../../assets/img/icons/email.svg" alt="">
                            <h4>Media</h4>
                        </router-link>
                    </li>
                     <li>
                        <router-link to="/Location">
                             <img class="icon" src="../../assets/img/icons/location.svg" alt="">
                            <h4>Member</h4>
                        </router-link>
                    </li>
                    <li v-if="userStore.authUser == null">
                        <router-link to="/member">
                             <img class="icon" src="../../assets/img/icons/member.svg" alt="">
                            <h4>Contact</h4>
                        </router-link>
                    </li>
                     <li v-if="userStore.authUser !== null && userStore.authUser.access_token">
                        <router-link to="/member/dashboard">
                             <img class="icon" src="../../assets/img/icons/member.svg" alt="">
                            <h4>Contact</h4>
                        </router-link>
                    </li>
                </ul>

            </nav>
        <!-- <div id="content">
             <div class="navbar-header">
                            <button type="button" id="sidebarCollapse" class="navbar-btn active">
                                <span></span>
                                <span></span>
                                <span></span>
                            </button>
                    </div>
            </div> -->
    </div>
     <!-- <quick-menu :menu-count=count :icon-class=icons :menu-url-list=list :position=position :background-color=backgroundColor :is-open-new-tab=isOpenNewTab></quick-menu> -->
     </div>
</template>

<script>

import quickMenu from 'vue-quick-menu';
import {mapState} from 'vuex';

export default {
  name: 'Nav',
  data(){
      return {
        count:4,
        icons:["fab fa-facebook-f","fab fa-twitter","fab fa-instagram","fab fa-youtube"],
        list:["https://www.facebook.com/Iglesia-de-Cristo-en-Elgin-243271119073381/","https://twitter.com/CristoElgin","https://www.instagram.com/cristoelgin/","https://www.youtube.com/user/TheCatch13777/featured"],
        backgroundColor:'#34495e',
        color:'#ffffff',
        position:'bottom-right',
        isOpenNewTab:true
      }
  },
  components: {
      'quick-menu' :quickMenu
  },
  methods: {
      checkUserLog(){
          console.log("clicked")
          
      }
  },
   computed: {
    ...mapState({
      userStore: state => state.userStore
    })
  }
}

</script>

<style lang="scss">
@import '../../assets/main';

svg {
    margin-top:15px!important;
}

img.logo {
    width: 90px;
    padding: 40px 0 10px 20px;

}

body {
    font-family: 'Poppins', sans-serif;
    background: #fafafa;
}

p {
    font-family: 'Poppins', sans-serif;
    font-size: 1.1em;
    font-weight: 300;
    line-height: 1.7em;
    color: #999;
}

a, a:hover, a:focus {
    color: inherit;
    text-decoration: none;
    transition: all 0.3s;
}
h4 {
    display: inline;
}

.navbar-btn {
    box-shadow: none;
    outline: none !important;
    border: none;
    position: fixed;
    border-radius: 50%;
}

.line {
    width: 100%;
    height: 1px;
    border-bottom: 1px dashed #ddd;
    margin: 40px 0;
}

.wrapper {
    display: flex;
    align-items: stretch;
}

#sidebar {
    background: $gradient;
    color: black;
    transition: all 0.3s;
    width: 100px;
    height: 100vh;

    ul {
        margin: 25px 0 0 0;
          li {
         padding: 1vh 0 3em 30px;
       .icon {
            width: 40px;
            left: 0;
        }
       
    }

    }
  
    


     h4{
            display: inline;
            opacity: 0;
            position: fixed;
            padding: 10px 0 0 40px;
            transition: width .2s;
        }
}

// #sidebar:hover {
//       width: 250px;
//       background-color: rosybrown;
      
//       h4{
//           opacity: 1;
//       }
// }

   
/* sub menu of study */

#studySub {
    position: absolute;
    display: inline-flex;
    margin-top: -70px;
    margin-left: -300px;
    transition: all .2s;
    
    li {
        
        border: solid black 2px;
        border-radius: 50%;
        margin-right: 10px;
        height: 60px;
        width: 60px;

        a{
        color: black;
        position: relative; 
        margin-top: 0px;
    }
        
    }
     
}
#studySub.active {
    margin-left: 50px;
}


 .fish {
        position: relative;
        width: 20px;
        left: 6px;
    }


</style>





