<template>
 <div class="container-fluid back boxshadow">

    <b-carousel id="carousel1"
                style="text-shadow: 1px 1px 2px #333;"
                controls
                indicators
                background="transparent"
                :interval="3000"
                img-width="1024"
                img-height="380"
                v-model="slide"
                @sliding-start="onSlideStart"
                @sliding-end="onSlideEnd"
    >

      <!-- Text slides with image -->
      <b-carousel-slide id="car" img-blank img-src="https://source.unsplash.com/daily?bible/1024x400">
        <h5 class="dailyVersesWrapper verses"></h5>
      </b-carousel-slide>

      <!-- Slides with custom text -->
      <b-carousel-slide id="car" img-blank img-src="https://source.unsplash.com/daily?landscape/1024x400">
           <h5 class="dailyVersesWrapper2 verses"></h5>
      </b-carousel-slide>

      <!-- Slides with image only -->
      <b-carousel-slide id="car" img-blank img-src="https://source.unsplash.com/daily?space/1024x400">
        <h5 class="dailyVersesWrapper3 verses"></h5>
      </b-carousel-slide>

      <!-- Slides with img slot -->
      <!-- Note the classes .d-block and .img-fluid to prevent browser default image alignment -->
      <b-carousel-slide id="car" img-blank img-src="https://source.unsplash.com/daily?awash-in-color/1024x400">
        <h5 class="dailyVersesWrapper4 verses"></h5>
      </b-carousel-slide>

      <!-- Slide with blank fluid image to maintain slide aspect ratio -->
      <b-carousel-slide id="car" img-blank img-src="https://source.unsplash.com/daily?patterns/1024x400">
        <h5 class="dailyVersesWrapper5 verses"></h5>
      </b-carousel-slide>

    </b-carousel>

    <!-- <p class="mt-4">
      Slide #: {{ slide }}<br>
      Sliding: {{ sliding }}
    </p> -->
          

  </div>
</template>

<script>

export default {
  name: 'Verses',
  data(){
      return{
          slide: 0,
          sliding: null
      }
  },
  methods: {
    onSlideStart (slide) {
      this.sliding = true
    },
    onSlideEnd (slide) {
      this.sliding = false
    },
      getVerses(){
          $(document).ready(function(){
          $.ajax({
               url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
               dataType: 'JSONP',
               success:function(json){
               $(".dailyVersesWrapper").prepend(json.html);
            }
            });
        $.ajax({
              url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
              dataType: 'JSONP',
              success:function(json){
               $(".dailyVersesWrapper2").prepend(json.html);
              }
           });
        $.ajax({
            url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
            dataType: 'JSONP',
            success:function(json){
             $(".dailyVersesWrapper3").prepend(json.html);
            }
         });
         $.ajax({
          url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
          dataType: 'JSONP',
          success:function(json){
           $(".dailyVersesWrapper4").prepend(json.html);
          }
        });
        $.ajax({
            url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
            dataType: 'JSONP',
            success:function(json){
            $(".dailyVersesWrapper5").prepend(json.html);
            }
        });
          });
      }
},
    mounted(){
        this.getVerses()
    }
}

</script>

<style  lang="scss" scoped>

    #carousel1{
      left:15px;
    
    }
    .back {
      background: rgba(247,107,91,1);
background: -moz-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.6) 100%);
background: -webkit-gradient(left top, right bottom, color-stop(0%, rgba(247,107,91,1)), color-stop(100%, rgba(90,147,245,0.6)));
background: -webkit-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.6) 100%);
background: -o-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.6) 100%);
background: -ms-linear-gradient(-45deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.6) 100%);
background: linear-gradient(135deg, rgba(247,107,91,1) 0%, rgba(90,147,245,0.6) 100%);
filter: progid:DXImageTransform.Microsoft.gradient( startColorstr='#f76b5b', endColorstr='#5a93f5', GradientType=1 );
    }
    #car {
        max-height: 300px;
        

        h5 {
            padding: 0 0 80px 0;
            font-size: 1.5em;
            color: white;
           
        } 
       

       
    }
</style>


