<template>
 <div style="margin-top: 20px;">
     <nav-component></nav-component>
     <div class="map">
         <div class="loader"></div>
        <iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d612.9787608429226!2d-88.30471043801387!3d42.03886171615099!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x880f0516292058c7%3A0x46f7a2a8a950e784!2sChurch+of+Christ!5e1!3m2!1sen!2sus!4v1516216451285"  frameborder="0" style="border:0" allowfullscreen></iframe>   </div>
    </div> 
</template>

<script>
import Nav from './main/Nav.vue';

export default {
  name: 'Location',
  components:{
    'nav-component': Nav
  },
  methods: {
      showMap(){
          setTimeout(function () {
                $("iframe").show()
                $(".loader").hide()
            }, 2000);
      }
  },
  mounted() {
      this.showMap()
  }
}
</script>

<style  lang="scss" scoped>
@import 'src/assets/main.scss';
    .map {
        position: relative;
        width: 92.5vw;
        height: 100vh;
        left:100px;
        overflow: hidden!important;
            background: $gradient-slant;
    }

    iframe{
        height: 100vh;
        width: 100vw;
        display: none;
    }

    .loader {
    background: transparent;
    border: 5px solid transparent; /* Light grey */
    border-top: 5px solid white; /* Blue */
    border-radius: 100%;
    top: 40vh;
    left: 40vw;
    position: relative;
    width: 100px;
    height: 100px;
    animation: spin 2s linear infinite;
}

@keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
}
</style>




