<template>
 <div style="margin-top: 20px;">
     <nav-component></nav-component>
     <h1>sdvgfsdfsdfsfsdfPage</h1>
      <v-calendar :attributes='attrs' is-single-paned  is-expanded> </v-calendar>
</div> 
</template>

<script>
import Nav from './main/Nav.vue';

export default {
  name: 'Events',
   data() {
    return {
         attrs: [
            {
            key: 'today',
            dates: { weekdays: [ 2] },
            highlight: {
                backgroundColor: '#ff8080',
                
            },
            // Just use a normal style
            contentStyle: {
                color: '#fafafa',
            },
            contentHoverStyle: {
                color: 'black'
            },
            // Our new popover here
            popover: {
                label: 'Cantos!',
            }
            },
            {
                key: 'salida',
                dates: [new Date(2018, 0, 12)],
                highlight: {
                    backgroundColor: 'yellow',
            } 
            }
      ],
    };
  },
  components:{
    'nav-component': Nav
  }
}
</script>

<style  lang="scss">

.c-pane-container {
    position: relative;
    left: 150px;
    width: 85vw!important;
    height: 70vh;


}
    .c-day{
        height: 70px!important;
    }

    .c-day-content{
        border-radius: 0px!important;
    }
</style>



