<template>
  <div style="margin-top: 20px;" v-if="userStore.authUser !== null && userStore.authUser.access_token">
      <nav-component></nav-component>
        <div class="container">
            <h1>dashboard</h1>
            <button class="btn" v-on:click="handleLogout()">logout</button>
        </div>
  </div>
</template>

<script>
import Nav from '../main/Nav.vue';
import {mapState} from 'vuex';

export default {
  name: 'Dashboard',
  components:{
    'nav-component': Nav
  },
   computed: {
    ...mapState({
      userStore: state => state.userStore
    })
  },
  methods: {
      handleLogout(){
          this.$store.dispatch('clearAuthUser')
          window.localStorage.removeItem('authUser')
          this.$router.push({path: '/member'})
      }
  }
}
</script>

<style lang="scss">

</style>



